let timer;
let element;
let dotNetRef;
let timeoutMs;
let events = ['mousemove', 'keydown', 'click', 'scroll', 'touchstart'];
let isIdle = false;

function resetTimer() {
    clearTimeout(timer);
    if (isIdle) {
        isIdle = false;
        dotNetRef.invokeMethodAsync('OnUserActive');
    }
    timer = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnUserIdle');
    }, timeoutMs);
}

export function initialize(el, ref, timeout) {
    element = el;
    dotNetRef = ref;
    timeoutMs = timeout;
    isIdle = false;

    events.forEach(evt => element.addEventListener(evt, resetTimer, { passive: true }));

    timer = setTimeout(() => {
        isIdle = true;
        dotNetRef.invokeMethodAsync('OnUserIdle');
    }, timeoutMs);
}

export function dispose() {
    clearTimeout(timer);
    if (element) {
        events.forEach(evt => element.removeEventListener(evt, resetTimer));
    }
    element = null;
    dotNetRef = null;
}

